const out = [];

const bin = $input.item.binary ?? {};
const fotoKeys = Object.keys(bin).filter(k => k.startsWith('Fotos_'));

for (const k of fotoKeys) {
  const b = bin[k];

  out.push({
    json: {
      originalKey: k,
      fileName: b.fileName,
      mimeType: b.mimeType,
    },
    binary: {
      // Normalizamos todo a "data" para que Edit Image use siempre la misma key
      data: b,
    },
  });
}

return out;

// Junta todos los items (cada uno con binary.data) en 1 solo item
// creando múltiples propiedades binarias: file_0, file_1, ...

const items = $input.all();

const mergedBinary = {};
const files = [];

items.forEach((it, i) => {
  const b = it.binary?.data;
  if (!b) return;

  const key = `file_${i}`;
  mergedBinary[key] = {
    ...b,
    // asegúrate que cada archivo tenga nombre único dentro del zip
    fileName: b.fileName || `foto_${i}.jpg`,
  };

  files.push({
    key,
    fileName: mergedBinary[key].fileName,
    mimeType: mergedBinary[key].mimeType,
  });
});

return [
  {
    json: {
      files,
      total: files.length,
    },
    binary: mergedBinary,
  },
];

